from functools import lru_cache
class Solution:
    def punishmentNumber(self, n):
        def ok(sq, target):
            digits = sq
            L = len(digits)
            @lru_cache(maxsize=None)
            def dp(idx, rem):
                if idx == L:
                    return rem == 0
                cur = 0
                for j in range(idx, L):
                    cur = cur * 10 + int(digits[j])
                    if cur > rem:
                        break
                    if dp(j + 1, rem - cur):
                        return True
                return False
            res = dp(0, target)
            dp.cache_clear()
            return res
        total = 0
        for i in range(1, n + 1):
            if ok(str(i * i), i):
                total += i * i
        return total

