class Solution:
    def punishmentNumber(self, n):
        def can_partition(s, target):
            if target < 0:
                return False
            if not s:
                return target == 0
            for i in range(1, len(s) + 1):
                piece = int(s[:i])
                if piece <= target and can_partition(s[i:], target - piece):
                    return True
            return False
        total = 0
        for i in range(1, n + 1):
            if can_partition(str(i * i), i):
                total += i * i
        return total

