var punishmentNumber = function(n) {
    function canPartition(s, target) {
        if (target < 0) return false;
        if (s.length === 0) return target === 0;
        for (let i = 1; i <= s.length; i++) {
            const piece = parseInt(s.slice(0, i), 10);
            if (piece <= target && canPartition(s.slice(i), target - piece)) {
                return true;
            }
        }
        return false;
    }
    let total = 0;
    for (let i = 1; i <= n; i++) {
        if (canPartition(String(i * i), i)) {
            total += i * i;
        }
    }
    return total;
